// 2. Automatyczny parser - odpala się tylko RAZ przy starcie serwera
private val tramDepotMap: Map<String, String> by lazy {
    val map = mutableMapOf<String, String>()
    // Regex szukający: [Cyfry] + spacja + [kod R-coś] LUB [UA]
    val regex = Regex("""(\d+)\s+(R-\d\s[A-Z]|UA)""")

    regex.findAll(rawTramData).forEach { matchResult ->
        val vehicleNumber = matchResult.groupValues[1]
        val code = matchResult.groupValues[2]

        map[vehicleNumber] = when (code) {
            "R-1 W" -> "Zajezdnia Wola"
            "R-2 P" -> "Zajezdnia Praga"
            "R-3 M" -> "Zajezdnia Mokotów"
            "R-4 Z" -> "Zajezdnia Żoliborz"
            "R-5 A" -> "Zajezdnia Annopol"
            "UA" -> "Nieokreślona (do uzupełnienia)"
            else -> "Nieokreślona (do uzupełnienia)"
        }
    }
    map
}

// 3. Nasza główna funkcja - teraz korzysta z potężnego słownika!
fun calculateDepot(vehicleNumber: String, isTram: Boolean): String {
    if (isTram) {
        // Jeśli znajdziemy tramwaj w słowniku - zwracamy go. Jeśli go tam nie ma, zwracamy UA.
        return tramDepotMap[vehicleNumber] ?: "Nieokreślona (do uzupełnienia)"
    } else {
        // Logika dla autobusów (zostawiamy starą, bo Excel dotyczył tramwajów)
        return when {
            vehicleNumber.startsWith("1") || vehicleNumber.startsWith("2") -> "Zajezdnia R-10 Ostrobramska"
            vehicleNumber.startsWith("3") || vehicleNumber.startsWith("4") -> "Zajezdnia R-13 Kleszczowa"
            vehicleNumber.startsWith("5") || vehicleNumber.startsWith("7") -> "Zajezdnia R-7 Woronicza"
            vehicleNumber.startsWith("9") -> "Mobilis / Arriva (Prywatny)"
            else -> "Zajezdnia MZA (Niezidentyfikowana)"
        }
    }
}

// Funkcja "udająca" zgadywanie pętli na podstawie kierunku
fun calculateExpectedEnd(lines: String): String {
    return "Trasa linii $lines (Wymaga GTFS)"
}
// --- NARZĘDZIE ADMINISTRACYJNE ---
// Zwraca posortowaną listę numerów tramwajów, które mają status UA / Nieokreślona
fun getUnknownTramsList(): List<String> {
    return tramDepotMap
        .filter { it.value == "Nieokreślona (do uzupełnienia)" }
        .map { it.key }
        .sorted()
}
